    "done_when": "grep -rn 'console.log' src/ returns no matches",
    "resume_by": "finish replacing remaining console.log calls in src/ with the new logger, then verify src/ is console.log-free"
  },
  "state": {
    "branch": "(no-git: plain filesystem)",
    "next_acceptance_check": "grep -rn 'console.log' src/ returns no matches",
    "worktree": {
      "root": "$HOME/Projects/my-projects/catalyst",
      "is_linked": false,
      "git_common_dir": "(none — not a git repo; tier-3 legacy slot)"
    },
    "decisions": [
      "Refactor centralizes logging behind the new logger; direct console.log in src/ is being removed",
      "No git in this working dir — handoff keyed to tier-3 legacy HANDOFF.json slot"
    ],
    "open_risks": [
      "console.log may remain in src/ files not yet visited; sweep all of src/ before declaring done"
    ]
  },
  "files_read_first": [
    {"path": "src/", "why": "sweep for remaining console.log calls — acceptance target"}
  ],
  "files_skip": [
    {"path": ".claude/PROJECT_STATE.md", "why": "historical narrative only; decisions above are binding"}
  ]
}

